member.example:
Bind the Selectable colors property using a serialized binder field — the target Selectable is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private SelectableColorBlockBinder _colors;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public ColorBlock _colors;
    }


Bind the Selectable colors property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Selectable _selectable;
        
        private SelectableColorBlockBinder Colors =>
            new(_selectable);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public ColorBlock _colors;
    }

Switch the Selectable colors between two values using a serialized binder field — the target Selectable is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private SelectableColorBlockSwitcherBinder _isSelected;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isSelected;
    }


Switch the Selectable colors between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Selectable _selectable;
        
        private SelectableColorBlockSwitcherBinder IsSelected => new(
            _selectable, _selectedColors, _defaultColors);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isSelected;
    }
